@using sv_f4dbb4a6db5a411681ff5b136ea95128.Services

<div class="change-password-panel">
    <button class="btn btn-outline-secondary btn-sm mb-2" @onclick="ToggleExpanded">
        @(IsExpanded ? "▾ Change Password" : "▸ Change Password")
    </button>

    @if (IsExpanded)
    {
        <div class="password-form mt-2">
            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger py-1 px-2 small">@errorMessage</div>
            }
            @if (!string.IsNullOrEmpty(successMessage))
            {
                <div class="alert alert-success py-1 px-2 small">@successMessage</div>
            }

            <div class="mb-2">
                <label class="form-label small">Current Password</label>
                <input type="password" class="form-control form-control-sm" @bind="currentPassword" />
            </div>
            <div class="mb-2">
                <label class="form-label small">New Password</label>
                <input type="password" class="form-control form-control-sm" @bind="newPassword" />
            </div>
            <div class="mb-2">
                <label class="form-label small">Confirm Password</label>
                <input type="password" class="form-control form-control-sm" @bind="confirmPassword" />
            </div>
            <button class="btn btn-primary btn-sm" @onclick="HandleUpdatePassword" disabled="@isSaving">
                @(isSaving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? errorMessage;
    private string? successMessage;
    private bool isSaving;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task HandleUpdatePassword()
    {
        errorMessage = null;
        successMessage = null;

        if (string.IsNullOrWhiteSpace(currentPassword) ||
            string.IsNullOrWhiteSpace(newPassword))
        {
            errorMessage = "All fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            errorMessage = "New password and confirmation do not match.";
            return;
        }

        if (newPassword.Length < 8)
        {
            errorMessage = "New password must be at least 8 characters.";
            return;
        }

        isSaving = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            successMessage = "Password updated successfully.";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isSaving = false;
        }
    }
}

@using sv_f4dbb4a6db5a411681ff5b136ea95128.Services

<tr>
    <td>@Session.Device</td>
    <td>@Session.Location</td>
    <td>@Session.LastActive.ToString("g")</td>
    <td>
        @if (!IsCurrent)
        {
            <button class="btn btn-outline-danger btn-sm" @onclick="HandleRevokeClicked">
                Revoke
            </button>
        }
        else
        {
            <span class="badge bg-success">Current</span>
        }
    </td>
</tr>

@code {
    [Parameter, EditorRequired]
    public ActiveSession Session { get; set; } = default!;

    [Parameter]
    public bool IsCurrent { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<ActiveSession> OnRevokeRequested { get; set; }

