            <h6>Live Preview</h6>
            <div class="live-preview p-3 rounded border"
                 style="@GetPreviewStyle()">
                <h5 style="margin-bottom: 0.5rem;">Preview Title</h5>
                <p style="margin-bottom: 0.5rem;">
                    This is how your content will look with the selected settings.
                </p>
                <button class="btn btn-sm btn-primary">Sample Button</button>
