+                <input type="email" class="form-control" @bind="email" />
+            </div>
+            <div class="mb-3">
+                <label class="form-label">Bio</label>
+                <textarea class="form-control" rows="3" @bind="bio"></textarea>
+            </div>
+        </div>
+        <div class="col-md-4 text-center">
+            <div class="avatar-preview mb-2">
+                <img src="@avatarUrl" alt="Avatar" class="rounded-circle"
+                     style="width:120px;height:120px;object-fit:cover;border:2px solid #dee2e6;" />
+            </div>
+            <small class="text-muted text-break">@avatarUrl</small>
+        </div>
+    </div>
+
+    <div class="d-flex gap-2 mt-2">
+        <button class="btn btn-primary" @onclick="HandleSave" disabled="@isSaving">
+            @(isSaving ? "Saving…" : "Save Changes")
+        </button>
+        <button class="btn btn-outline-secondary" @onclick="HandleDiscard">
+            Discard Changes
+        </button>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired]
+    public UserProfile Profile { get; set; } = default!;
+
+    [Parameter, EditorRequired]
+    public EventCallback<UserProfile> OnSave { get; set; }
+
+    private string displayName = "";
+    private string email = "";
+    private string avatarUrl = "";
+    private string bio = "";
+    private string? statusMessage;
+    private bool isError;
+    private bool isSaving;
+
+    protected override void OnParametersSet()
+    {
+        if (!hasInitialized)
+        {
+            LoadFromProfile();
+            hasInitialized = true;
+        }
+    }
+
+    private bool hasInitialized;
+
+    private void LoadFromProfile()
+    {
+        displayName = Profile.DisplayName;
+        email = Profile.Email;
+        avatarUrl = Profile.AvatarUrl;
+        bio = Profile.Bio;
+    }
+
+    private void HandleDiscard()
+    {
+        LoadFromProfile();
+        statusMessage = null;
+    }
+
+    private async Task HandleSave()
+    {
+        isSaving = true;
+        statusMessage = null;
