@using sv_f4dbb4a6db5a411681ff5b136ea95128.Services

<div class="settings-section">
    <h4>Notifications</h4>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success py-1 px-2 small" role="alert">@statusMessage</div>
    }

    <div class="mb-3">
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h6>Muted Channels</h6>
    <div class="mb-3">
        @foreach (var channel in channels)
        {
            <div class="form-check mb-1">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@mutedChannels.Contains(channel)"
                       @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="HandleSave" disabled="@isSaving">
        @(isSaving ? "Saving…" : "Save Preferences")
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public NotificationPrefs Prefs { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private List<string> channels = new();
    private string? statusMessage;
    private bool isSaving;
    private bool hasInitialized;

    protected override void OnParametersSet()
    {
        if (!hasInitialized)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            channels = new List<string>(Prefs.MutedChannels);
            mutedChannels = new HashSet<string>(Prefs.MutedChannels);
            hasInitialized = true;
        }
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task HandleSave()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                emailNotifications, pushNotifications, weeklyDigest,
                mutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            statusMessage = "Notification preferences saved.";
        }
        finally
        {
            isSaving = false;
        }
    }
}

