@using sv_f4dbb4a6db5a411681ff5b136ea95128.Services

<div class="settings-section">
    <h4>Security</h4>

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <hr />

    <div class="mb-3">
        <h6>Two-Factor Authentication</h6>
        <div class="d-flex align-items-center gap-2">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@Security.TwoFactorEnabled" disabled />
                <label class="form-check-label" for="twoFactor">
                    @(Security.TwoFactorEnabled ? "Enabled" : "Disabled")
                </label>
            </div>
            @if (Security.TwoFactorEnabled)
            {
                <span class="badge bg-success">Active</span>
            }
            else
            {
                <span class="badge bg-secondary">Inactive</span>
            }
        </div>
        @if (Security.LastPasswordChange.HasValue)
        {
            <small class="text-muted d-block mt-1">
                Last password change: @Security.LastPasswordChange.Value.ToString("d")
            </small>
        }
    </div>

    <hr />

    <h6>Active Sessions</h6>
    <div class="table-responsive">
        <table class="table table-sm table-hover">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Security.Sessions)
                {
                    <ActiveSessionRow Session="session"
                                      IsCurrent="@(session.Id == currentSessionId)"
                                      OnRevokeRequested="ShowRevokeDialog" />
                }
            </tbody>
        </table>
    </div>

    <RevokeSessionDialog IsVisible="showRevokeDialog"
                         Session="sessionToRevoke"
                         OnConfirm="HandleRevokeConfirmed"
                         OnCancel="HideRevokeDialog" />
</div>

@code {
    [Parameter, EditorRequired]
    public SecuritySettings Security { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevokeSession { get; set; }

    // Treat the first session as "current" for demo purposes
    private string currentSessionId => Security.Sessions.FirstOrDefault()?.Id ?? "";

    private bool showRevokeDialog;
    private ActiveSession? sessionToRevoke;

    private void ShowRevokeDialog(ActiveSession session)
    {
        sessionToRevoke = session;
        showRevokeDialog = true;
    }

    private void HideRevokeDialog()
    {
        showRevokeDialog = false;
        sessionToRevoke = null;
    }

    private async Task HandleRevokeConfirmed(ActiveSession session)
    {
        showRevokeDialog = false;
        sessionToRevoke = null;
        await OnRevokeSession.InvokeAsync(session.Id);
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }
}

@using sv_f4dbb4a6db5a411681ff5b136ea95128.Services

<div class="settings-section">
    <h4>Appearance</h4>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success py-1 px-2 small" role="alert">@statusMessage</div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-3">
                <h6>Theme</h6>
                @foreach (var t in themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{t}")" value="@t"
                               checked="@(theme == t)"
                               @onchange="@(() => theme = t)" />
                        <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                    </div>
                }
            </div>

            <div class="mb-3">
                <h6>Font Size</h6>
                @foreach (var fs in fontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{fs}")" value="@fs"
                               checked="@(fontSize == fs)"
                               @onchange="@(() => fontSize = fs)" />
                        <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                    </div>
                }
            </div>

            <div class="mb-3">
                <h6>Language</h6>
                <select class="form-select form-select-sm" @bind="language">
                    @foreach (var lang in languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="mb-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="HandleSave" disabled="@isSaving">
                @(isSaving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <h6>Live Preview</h6>
            <div class="live-preview p-3 rounded border"
                 style="@GetPreviewStyle()">
                <h5 style="margin-bottom: 0.5rem;">Preview Title</h5>
                <p style="margin-bottom: 0.5rem;">
                    This is how your content will look with the selected settings.
                </p>
                <button class="btn btn-sm btn-primary">Sample Button</button>
                @if (compactMode)
                {
                    <span class="ms-2 badge bg-info">Compact</span>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public AppearanceSettings Settings { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "English";
    private bool compactMode;
    private string? statusMessage;
    private bool isSaving;
    private bool hasInitialized;

    private readonly string[] themes = { "Light", "Dark", "System" };
    private readonly string[] fontSizes = { "Small", "Medium", "Large" };
    private readonly string[] languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    protected override void OnParametersSet()
    {
        if (!hasInitialized)
        {
            theme = Settings.Theme;
            fontSize = Settings.FontSize;
            language = Settings.Language;
            compactMode = Settings.CompactMode;
            hasInitialized = true;
        }
    }

    private string GetPreviewStyle()
    {
        var bg = theme switch
        {
            "Dark" => "background-color:#1e1e1e;color:#d4d4d4;",
            "System" => "background-color:#f0f0f0;color:#333;",
            _ => "background-color:#ffffff;color:#212529;"
        };

        var fs = fontSize switch
        {
            "Small" => "font-size:0.85rem;",
            "Large" => "font-size:1.15rem;",
            _ => "font-size:1rem;"
        };

        var padding = compactMode ? "padding:0.5rem !important;" : "";

        return $"{bg}{fs}{padding}";
    }

    private async Task HandleSave()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Appearance settings saved.";
        }
        finally
        {
            isSaving = false;
        }
    }
}

