@page "/settings"
@using sv_f4dbb4a6db5a411681ff5b136ea95128.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar" aria-label="Settings navigation">
        <ul class="nav flex-column">
            @foreach (var section in sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(activeSection == section.Key ? "active" : "")"
                            @onclick="@(() => SelectSection(section.Key))">
                        <span class="settings-nav-icon">@section.Icon</span>
                        @section.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else
        {
            @switch (activeSection)
            {
                case "profile" when profile is not null:
                    <SettingsProfileSection Profile="profile" OnSave="HandleProfileSave" />
                    break;

                case "notifications" when notificationPrefs is not null:
                    <SettingsNotificationsSection Prefs="notificationPrefs" OnSave="HandleNotificationsSave" />
                    break;

                case "security" when security is not null:
                    <SettingsSecuritySection Security="security"
                                            OnChangePassword="HandleChangePassword"
                                            OnRevokeSession="HandleRevokeSession" />
                    break;

                case "appearance" when appearance is not null:
                    <SettingsAppearanceSection Settings="appearance" OnSave="HandleAppearanceSave" />
                    break;
            }
        }
    </div>
</div>

@code {
    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] sections =
    {
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    };

    private string activeSection = "profile";
    private bool isLoading = true;

    private UserProfile? profile;
    private NotificationPrefs? notificationPrefs;
    private SecuritySettings? security;
    private AppearanceSettings? appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadSection(activeSection);
    }

    private async Task SelectSection(string section)
    {
        if (activeSection == section) return;
        activeSection = section;
        await LoadSection(section);
    }

    private async Task LoadSection(string section)
    {
        isLoading = true;
        switch (section)
        {
            case "profile":
                profile = await SettingsService.GetProfileAsync();
                break;
            case "notifications":
                notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
                break;
            case "security":
                security = await SettingsService.GetSecuritySettingsAsync();
                break;
            case "appearance":
                appearance = await SettingsService.GetAppearanceAsync();
                break;
        }
        isLoading = false;
    }

    private async Task HandleProfileSave(UserProfile updated)
    {
        await SettingsService.SaveProfileAsync(updated);
        profile = updated;
    }

    private async Task HandleNotificationsSave(NotificationPrefs updated)
    {
        await SettingsService.SaveNotificationPrefsAsync(updated);
        notificationPrefs = updated;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleAppearanceSave(AppearanceSettings updated)
    {
        await SettingsService.SaveAppearanceAsync(updated);
        appearance = updated;
    }
}

.settings-dashboard {
    display: flex;
    gap: 1.5rem;
    min-height: 500px;
}

.settings-sidebar {
    min-width: 200px;
    max-width: 220px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

.settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0.375rem;
    padding: 0.5rem 0.75rem;
    margin-bottom: 0.25rem;
    cursor: pointer;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.settings-sidebar .nav-link:hover {
    background-color: #f8f9fa;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

.settings-nav-icon {
    font-size: 1.1rem;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

.settings-section h4 {
    margin-bottom: 1rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid #dee2e6;
}

::deep .modal-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.4);
    z-index: 1040;
}

::deep .modal.d-block {
    position: fixed;
    inset: 0;
    z-index: 1050;
    display: flex !important;
    align-items: center;
    justify-content: center;
}

.live-preview {
    min-height: 120px;
    transition: all 0.2s ease;
}

