toolArgs.file_text:
.settings-dashboard {
    display: flex;
    gap: 1.5rem;
    min-height: 500px;
}

.settings-sidebar {
    min-width: 200px;
    max-width: 220px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

.settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0.375rem;
    padding: 0.5rem 0.75rem;
    margin-bottom: 0.25rem;
    cursor: pointer;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.settings-sidebar .nav-link:hover {
    background-color: #f8f9fa;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

.settings-nav-icon {
    font-size: 1.1rem;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

.settings-section h4 {
    margin-bottom: 1rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid #dee2e6;
}

::deep .modal-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.4);
    z-index: 1040;
}

::deep .modal.d-block {
    position: fixed;
    inset: 0;
    z-index: 1050;
    display: flex !important;
    align-items: center;
    justify-content: center;
}

.live-preview {
    min-height: 120px;
    transition: all 0.2s ease;
}

